import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;
import java.util.stream.Collectors;

public class TestRunner {
    static int passed = 0;
    static int failed = 0;

    public static void main(String[] args) {

        // Mirror the same data as the student file so we can compute expected values.
        ArrayList<Mermaid> mermaids = new ArrayList<>();
        mermaids.add(new Mermaid("Ariel",  150, "Atlantic"));
        mermaids.add(new Mermaid("Marina", 220, "Pacific"));
        mermaids.add(new Mermaid("Coral",  180, "Atlantic"));
        mermaids.add(new Mermaid("Pearl",   95, "Indian"));
        mermaids.add(new Mermaid("Nixie",  310, "Arctic"));

        ArrayList<Ship> fleet = new ArrayList<>();
        fleet.add(new Ship("Ocean Star",  25, 5000));
        fleet.add(new Ship("Wave Runner", 18, 3000));
        fleet.add(new Ship("Sea Dragon",  32, 7000));
        fleet.add(new Ship("Coral Queen", 22, 4500));

        // ── (1) totalAge ──
        // 150+220+180+95+310 = 955
        check("(1) totalAge", "955",
              String.valueOf(mermaids.stream().mapToInt(m -> m.getAge()).sum()));

        // ── (2) oldestAge ──
        // max is 310 (Nixie)
        check("(2) oldestAge", "310",
              String.valueOf(mermaids.stream().mapToInt(m -> m.getAge()).max().getAsInt()));

        // ── (3) avgSpeed ──
        // (25+18+32+22)/4 = 97/4 = 24.25
        check("(3) avgSpeed", "24.25",
              String.valueOf(fleet.stream().mapToInt(s -> s.getSpeed()).average().getAsDouble()));

        // ── (4) fastCapacity ──
        // ships with speed > 20: Ocean Star(5000), Sea Dragon(7000), Coral Queen(4500) = 16500
        check("(4) fastCapacity", "16500",
              String.valueOf(fleet.stream()
                  .filter(s -> s.getSpeed() > 20)
                  .mapToInt(s -> s.getCargoCapacity())
                  .sum()));

        // ── (5) oldestThree ──
        // Sorted by age desc: Nixie(310), Marina(220), Coral(180)
        List<String> expectedThree = List.of("Nixie", "Marina", "Coral");
        List<String> actualThree = mermaids.stream()
            .sorted(Comparator.comparing((Mermaid m) -> m.getAge()).reversed())
            .limit(3)
            .map(m -> m.getName())
            .collect(Collectors.toList());
        check("(5) oldestThree", expectedThree.toString(), actualThree.toString());

        // ── (6) minFastSpeed ──
        // ships with speed > 20: 25, 32, 22 — minimum is 22
        check("(6) minFastSpeed", "22",
              String.valueOf(fleet.stream()
                  .filter(s -> s.getSpeed() > 20)
                  .mapToInt(s -> s.getSpeed())
                  .min().getAsInt()));

        // ── summary ──
        System.out.println();
        int total = passed + failed;
        System.out.println((passed == total ? "PASS" : "FAIL")
            + ": " + passed + "/" + total + " tests passed");
    }

    static void check(String label, String expected, String actual) {
        if (expected.equals(actual)) {
            System.out.println("PASS: " + label); passed++;
        } else {
            System.out.println("FAIL: " + label
                + " \u2014 expected \"" + expected
                + "\" but got \"" + actual + "\""); failed++;
        }
    }
}
